// packages/cli/src/core/auth.ts
async function performInitialAuth(config, authType) {
  if (!authType) {
    return { authError: null, accountSuspensionInfo: null };
  }
  try {
    await config.refreshAuth(authType);
  } catch (e) {
    if (e instanceof ValidationRequiredError) {
      return { authError: null, accountSuspensionInfo: null };
    }
    const suspendedError = isAccountSuspendedError(e);
    if (suspendedError) {
      return {
        authError: null,
        accountSuspensionInfo: {
          message: suspendedError.message,
          appealUrl: suspendedError.appealUrl,
          appealLinkText: suspendedError.appealLinkText
        }
      };
    }
    if (e instanceof ProjectIdRequiredError) {
      return {
        authError: getErrorMessage(e),
        accountSuspensionInfo: null
      };
    }
    return {
      authError: `Failed to sign in. Message: ${getErrorMessage(e)}`,
      accountSuspensionInfo: null
    };
  }
  return { authError: null, accountSuspensionInfo: null };
}

// packages/cli/src/core/theme.ts
function validateTheme(settings) {
  const effectiveTheme = settings.merged.ui.theme;
  if (effectiveTheme && !themeManager.findThemeByName(effectiveTheme)) {
    return `Theme "${effectiveTheme}" not found.`;
  }
  return null;
}

// packages/cli/src/core/initializer.ts
async function initializeApp(config, settings) {
  const authHandle = startupProfiler.start("authenticate");
  const { authError, accountSuspensionInfo } = await performInitialAuth(
    config,
    settings.merged.security.auth.selectedType
  );
  authHandle?.end();
  const themeError = validateTheme(settings);
  const shouldOpenAuthDialog = settings.merged.security.auth.selectedType === void 0 || !!authError;
  logCliConfiguration(
    config,
    new StartSessionEvent(config, config.getToolRegistry())
  );
  if (config.getIdeMode()) {
    IdeClient.getInstance().then(async (ideClient) => {
      await ideClient.connect();
      logIdeConnection(
        config,
        new IdeConnectionEvent(IdeConnectionType.START)
      );
    }).catch((e) => {
      debugLogger.error("Failed to initialize IDE client:", e);
    });
  }
  return {
    authError,
    accountSuspensionInfo,
    themeError,
    shouldOpenAuthDialog,
    geminiMdFileCount: config.getGeminiMdFileCount()
  };
}

// packages/cli/src/config/auth.ts
function validateAuthMethod(authMethod) {
  loadEnvironment(loadSettings().merged, process.cwd());
  if (authMethod === AuthType.OLLAMA || authMethod === AuthType.LM_STUDIO || authMethod === AuthType.LLAMA_CPP || authMethod === AuthType.GGUF || authMethod === AuthType.MLX) {
    return null;
  }
  if (authMethod === AuthType.LOGIN_WITH_GOOGLE || authMethod === AuthType.COMPUTE_ADC || authMethod === AuthType.USE_GEMINI || authMethod === AuthType.USE_VERTEX_AI) {
    return null;
  }
  return "Invalid auth method selected. Please use a local provider (Ollama, LM Studio, etc).";
}

